import base64,os,subprocess,time,urllib.request,json
WEB='/home/k/vnt-web'
MP='/mnt/vnt-data/FileServer/VNT_World_AI_Division/MemPalace.md'
os.makedirs(WEB+'/generated',exist_ok=True)
os.makedirs(WEB+'/games',exist_ok=True)
os.makedirs(WEB+'/downloads',exist_ok=True)

# Write the portal (index.html = same page, all tabs)
html=base64.b64decode('')
open(WEB+'/index.html','wb').write(html)
open(WEB+'/media.html','wb').write(html)  # same page, opens to media tab
print('Written: '+str(len(html))+' bytes')

# Verify portal server running
try:
    urllib.request.urlopen('http://127.0.0.1:8888/',timeout=5)
    print('Port 8888: already serving')
except:
    print('Starting portal server...')
    subprocess.run(['fuser','-k','8888/tcp'],capture_output=True)
    time.sleep(1)
    subprocess.Popen(['/usr/bin/python3',WEB+'/portal_server.py'],
        stdout=open('/tmp/portal.log','w'),stderr=subprocess.STDOUT)
    time.sleep(4)
    try:
        urllib.request.urlopen('http://127.0.0.1:8888/',timeout=5)
        print('Port 8888: NOW SERVING')
    except Exception as e:
        print('Port 8888 failed:',e)
        print(open('/tmp/portal.log').read()[-300:])

# Test proxy
try:
    with urllib.request.urlopen('http://127.0.0.1:8888/api/health',timeout=8) as r:
        d=json.loads(r.read())
        print('Proxy OK:',json.dumps(d)[:60])
except Exception as e:
    print('Proxy:',str(e)[:60])

open(MP,'a').write('\nPortal final design deployed. Dark navy theme, sidebar, tabs, responsive.\n')
print('DONE: http://192.168.10.96:8888/')
print('Hard refresh: Ctrl+Shift+R')
